`dashboard/app/api/repos/route.ts`

### 実装内容

```typescript
import { NextResponse } from 'next/server'

import { fetchUserRepos } from '@/lib/github'

export async function GET() {
  try {
    const repos = await fetchUserRepos()
    return NextResponse.json({ repos })
  } catch (error) {
    const message = error instanceof Error ? error.message : 'Failed to fetch repos'
    return NextResponse.json({ error: message }, { status: 500 })
  }
}
```

### レスポンス形式

成功時:
```json
{
  "repos": [
    {
      "id": 123456,
      "name": "dot-claude-dev",
      "full_name": "ryryo/dot-claude-dev",
      "private": false,
      "description": "...",
      "updated_at": "2026-04-09T00:00:00Z",
      "html_url": "https://github.com/ryryo/dot-claude-dev"
    }
  ]
}
```

失敗時（500）:
```json
{ "error": "GitHub API error: 401 Unauthorized" }
```

