### 新実装

```typescript
import { NextResponse } from 'next/server'

import { fetchPlanFiles } from '@/lib/github'
import type { PlanFile, RepoError } from '@/lib/types'

export async function GET(request: Request) {
  const { searchParams } = new URL(request.url)
  const reposParam = searchParams.get('repos')

  if (!reposParam?.trim()) {
    return NextResponse.json({ plans: [], errors: [] })
  }

  const repos = reposParam.split(',').map((r) => r.trim()).filter(Boolean)

  const results = await Promise.allSettled(
    repos.map(async (fullName) => {
      const slashIndex = fullName.indexOf('/')
      if (slashIndex === -1) throw new Error(`Invalid repo format: ${fullName}`)
      const owner = fullName.slice(0, slashIndex)
      const repo = fullName.slice(slashIndex + 1)
      return fetchPlanFiles(owner, repo)
    }),
  )

  const plans: PlanFile[] = []
  const errors: RepoError[] = []

  results.forEach((result, index) => {
    if (result.status === 'fulfilled') {
      plans.push(...result.value)
    } else {
      errors.push({
        repo: repos[index],
        message: result.reason instanceof Error ? result.reason.message : 'Unknown error',
      })
    }
  })

  return NextResponse.json({ plans, errors })
}
```

### レスポンス形式

```json
{
  "plans": [ /* PlanFile[] */ ],
  "errors": [
    { "repo": "ryryo/private-repo", "message": "Failed to fetch contents at docs/PLAN: 403" }
  ]
}
```

### 注意点
- `repos` が未指定（初回ロード前など）の場合は空を返す
- `Promise.allSettled` で部分成功を許容する
- `owner`/`repo` の分割は `.indexOf('/')` で行い、正規表現を避けてシンプルに保つ

## 実装手順

### 新規作成ファイル
`dashboard/components/repo-selector.tsx`

### LocalStorage スキーマ
- キー: `plan-dashboard-selected-repos`
- 値: `JSON.stringify(string[])` — full_name の配列 (例: `["ryryo/dot-claude-dev"]`)

### Props 定義

```typescript
interface RepoSelectorProps {
  repos: GitHubRepo[]           // /api/repos から取得した全リポジトリ
  selected: string[]            // 選択中の full_name 配列
  onToggle: (fullName: string) => void
  planCounts: Record<string, number>  // full_name → plan数
  errorRepos: string[]          // fetch エラーになったリポジトリの full_name
}
```

### 実装内容

```tsx
'use client'

import { Badge } from '@/components/ui/badge'
import { Checkbox } from '@/components/ui/checkbox'
import type { GitHubRepo } from '@/lib/types'

interface RepoSelectorProps {
  repos: GitHubRepo[]
  selected: string[]
  onToggle: (fullName: string) => void
  planCounts: Record<string, number>
  errorRepos: string[]
}

export function RepoSelector({ repos, selected, onToggle, planCounts, errorRepos }: RepoSelectorProps) {
  return (
    <div className="space-y-1">
      <p className="text-label font-medium text-muted-foreground mb-2">リポジトリ</p>
      {repos.map((repo) => {
        const isSelected = selected.includes(repo.full_name)
        const count = planCounts[repo.full_name] ?? 0
        const hasError = errorRepos.includes(repo.full_name)
        return (
          <div
            key={repo.full_name}
            className="flex items-center gap-2 rounded-lg px-2 py-1.5 hover:bg-muted/50 cursor-pointer"
            onClick={() => onToggle(repo.full_name)}
          >
            <Checkbox
              checked={isSelected}
              onCheckedChange={() => onToggle(repo.full_name)}
              onClick={(e) => e.stopPropagation()}
            />
            <span className="text-sm flex-1 truncate" title={repo.full_name}>
              {repo.name}
            </span>
            {hasError && (
              <Badge variant="destructive" className="text-xs px-1 py-0">Error</Badge>
            )}
            {!hasError && count > 0 && (
              <Badge variant="secondary" className="text-xs tabular-nums">{count}</Badge>
            )}
          </div>
        )
      })}
    </div>
  )
}
```

### 注意点
- LocalStorage の読み書きは `app/page.tsx` 側で行う（このコンポーネントは純粋な表示コンポーネント）
- `repo.name`（短縮名）を表示し、`title` 属性でフルネームを見せる
- エラーリポジトリは赤バッジ `Error` を表示
- PLAN 数は `planCounts` から取得（0 件は何も表示しない）

## 実装手順

### 対象ファイル
`dashboard/app/page.tsx`

### 変更の全体像

1. `/api/repos` を SWR で取得（GitHubRepo 一覧）
2. LocalStorage からの選択復元・保存ロジックを追加
3. `/api/plans` の URL を動的に構築（`?repos=...`）
4. `ProjectFilter` を `RepoSelector` に置き換え
5. `errors` 配列を受け取りエラーリポジトリを追跡

### 新しい型・定数

```typescript
const STORAGE_KEY = 'plan-dashboard-selected-repos'

interface ReposResponse {
  repos: GitHubRepo[]
}

interface PlansResponse {
  plans: PlanFile[]
  errors: RepoError[]
}
```

### SWR の変更点

```typescript
// 1. リポジトリ一覧取得（常に実行）
const { data: reposData, isLoading: reposLoading } = useSWR<ReposResponse>(
  '/api/repos',
  fetcher,
)

// 2. 選択リポジトリのプラン取得（選択済みリポジトリがある場合のみ）
const plansUrl = selectedRepos.length > 0
  ? `/api/plans?repos=${selectedRepos.join(',')}`
  : null  // null を渡すと SWR はリクエストしない

const { data: plansData, isLoading: plansLoading } = useSWR<PlansResponse>(
  plansUrl,
  fetcher,
)
```

### LocalStorage の読み書き

```typescript
// 初期化: LocalStorage から復元
const [selectedRepos, setSelectedRepos] = useState<string[]>(() => {
  if (typeof window === 'undefined') return []
  try {
    const saved = localStorage.getItem(STORAGE_KEY)
    return saved ? (JSON.parse(saved) as string[]) : []
  } catch {
    return []
  }
})

// 変更時: LocalStorage に保存
const handleToggleRepo = (fullName: string) => {
  setSelectedRepos((current) => {
    const next = current.includes(fullName)
      ? current.filter((r) => r !== fullName)
      : [...current, fullName]
    localStorage.setItem(STORAGE_KEY, JSON.stringify(next))
    return next
  })
}
```

### ローディング状態

`reposLoading` が true の間は `SkeletonDashboard` を表示する（既存と同様）。

### filterContent の変更

```tsx
const filterContent = (
  <RepoSelector
    repos={reposData?.repos ?? []}
    selected={selectedRepos}
    onToggle={handleToggleRepo}
    planCounts={planCounts}
    errorRepos={(plansData?.errors ?? []).map((e) => e.repo)}
  />
)
```

### planCounts の計算

```typescript
const planCounts = useMemo(() => {
  const counts: Record<string, number> = {}
  ;(plansData?.plans ?? []).forEach((plan) => {
    counts[plan.projectName] = (counts[plan.projectName] ?? 0) + 1
  })
  return counts
}, [plansData?.plans])
```

### 既存コードとの互換性

- `filteredPlans` の計算は `plansData?.plans` ベースに変更（`data?.plans` → `plansData?.plans`）
- `selectedProjectCount` は `selectedRepos.length` に変更
- `statusCounts`, `overallProgress` の計算ロジックは変更なし
- `KanbanBoard` / `DashboardLayout` への props は変更なし

